mcp:tool-listener.mcp:parameters-schema:
{
        "type": "object",
        "properties": {
          "patientId": {
            "type": "string",
            "description": "Patient ID with EHR prefix (e.g., cs-abc12345 for CareStack, mt-def67890 for Meditab)"
          }
        },
        "required": ["patientId"]
      }

{
        "type": "object",
        "properties": {
          "code": {
            "type": "string",
            "description": "ICD-10 or SNOMED condition code (e.g., E11.9 for Type 2 Diabetes, I10 for Hypertension)"
          }
        },
        "required": ["code"]
      }

